        "import streamlit as st\n",
        "import pandas as pd\n",
        "import seaborn as sns\n",
        "import matplotlib.pyplot as plt\n",
        "\n",
        "# 1. Título do Dashboard\n",
        "st.title('Dashboard de Eficiência Energética Automotiva')\n",
        "\n",
        "# 2. Carregamento do Data (use @st.cache_data para o dashboard ficar rápido)\n",
        "@st.cache_data\n",
        "def carregar_dados():\n",
        "    data = pd.read_csv('seu_arquivo.csv')\n",
        "    # ... aqui você coloca suas limpezas (SRT -> DODGE, conversões, etc)\n",
        "    return data\n",
        "\n",
        "data = carregar_dados()\n",
        "\n",
        "# 3. Sidebar (Menu lateral para filtros)\n",
